// 直接在 n8n 中执行 Athena 查询
const AWS = require('aws-sdk');

// AWS 配置
AWS.config.update({
  region: 'us-west-2',
  accessKeyId: 'AKIAQQJLCWBOOKC7J6ZI',
  secretAccessKey: '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'
});

const athena = new AWS.Athena();

// 你的具体 SQL 查询
const sqlQuery = `SELECT id, uid, merchant_id, game_id, game_code, result, currency, ROUND(CAST(amount AS DOUBLE), 2) AS amount, ROUND(CAST(pay_out AS DOUBLE), 2) AS pay_out, multiplier, balance, detail, DATE_FORMAT(FROM_UNIXTIME(created_at / 1000), '%Y-%m-%d %H:%i:%s') AS created_at, DATE_FORMAT(FROM_UNIXTIME(updated_at / 1000), '%Y-%m-%d %H:%i:%s') AS updated_at FROM game_records WHERE provider = 'gp' AND merchant = '1737978166' AND id in ('1976423513265401856','1976422629802373120','1976437176340557824') AND updated_at BETWEEN TO_UNIXTIME(PARSE_DATETIME('2025-10-01 00:00:00', 'yyyy-MM-dd HH:mm:ss')) * 1000 AND TO_UNIXTIME(PARSE_DATETIME('2025-10-30 23:59:59', 'yyyy-MM-dd HH:mm:ss')) * 1000`;

// 启动查询
const startParams = {
  QueryString: sqlQuery,
  QueryExecutionContext: {
    Database: 'gmp'
  },
  ResultConfiguration: {
    OutputLocation: 's3://aws-athena-query-results-us-west-2-034986963036/'
  },
  WorkGroup: 'primary'
};

try {
  console.log('Starting Athena query...');
  const startResult = await athena.startQueryExecution(startParams).promise();
  const queryId = startResult.QueryExecutionId;

  console.log('Query started with ID:', queryId);

  // 等待查询完成
  let attempts = 0;
  const maxAttempts = 30; // 最多等待 5 分钟 (30 * 10秒)

  while (attempts < maxAttempts) {
    await new Promise(resolve => setTimeout(resolve, 10000)); // 等待 10 秒
    attempts++;

    try {
      const statusResult = await athena.getQueryExecution({ QueryExecutionId: queryId }).promise();
      const status = statusResult.QueryExecution.Status.State;

      console.log(`Attempt ${attempts}: Query status = ${status}`);

      if (status === 'SUCCEEDED') {
        // 查询成功，获取结果
        const resultParams = {
          QueryExecutionId: queryId,
          MaxResults: 1000
        };

        const result = await athena.getQueryResults(resultParams).promise();

        // 处理结果
        const columns = result.ResultSet.ResultSetMetadata.ColumnInfo.map(col => col.Name);
        const rows = result.ResultSet.Rows.slice(1).map(row => {
          const rowData = {};
          row.Data.forEach((cell, index) => {
            rowData[columns[index]] = cell.VarCharValue || null;
          });
          return rowData;
        });

        return {
          json: {
            success: true,
            queryId,
            status: 'completed',
            rowCount: rows.length,
            columns,
            data: rows,
            message: `查询成功！返回 ${rows.length} 条记录`,
            executionTime: `${attempts * 10} 秒`,
            timestamp: new Date().toISOString()
          }
        };

      } else if (status === 'FAILED' || status === 'CANCELLED') {
        return {
          json: {
            success: false,
            queryId,
            status: status.toLowerCase(),
            error: statusResult.QueryExecution.Status.StateChangeReason || 'Query failed',
            message: '查询执行失败',
            timestamp: new Date().toISOString()
          }
        };
      }
      // 如果状态是 RUNNING 或 QUEUED，继续等待

    } catch (statusError) {
      console.error('Error checking status:', statusError);
      return {
        json: {
          success: false,
          queryId,
          error: statusError.message,
          status: 'error',
          message: '检查查询状态时出错',
          timestamp: new Date().toISOString()
        }
      };
    }
  }

  // 超时
  return {
    json: {
      success: false,
      queryId,
      status: 'timeout',
      error: '查询超时',
      message: '查询执行超过5分钟，请检查查询条件',
      timestamp: new Date().toISOString()
    }
  };

} catch (error) {
  console.error('Error executing query:', error);
  return {
    json: {
      success: false,
      error: error.message,
      status: 'failed',
      message: '启动查询时出错',
      timestamp: new Date().toISOString()
    }
  };
}

// 格式化输出结果
const data = $json;

if (data.success) {
  // 成功结果格式化
  const formattedData = {
    success: true,
    message: data.message,
    queryId: data.queryId,
    summary: {
      rowCount: data.rowCount,
      columns: data.columns,
      executionTime: data.executionTime
    },
    data: data.data,
    timestamp: data.timestamp
  };

  // 如果有数据，显示前几行作为预览
  if (data.data && data.data.length > 0) {
    formattedData.preview = data.data.slice(0, 3); // 显示前3行
    formattedData.message += `\n\n数据预览 (前3行):`;
  }

  return { json: formattedData };
} else {
  // 错误结果格式化
  return {
    json: {
      success: false,
      message: data.message,
      error: data.error,
      queryId: data.queryId,
      status: data.status,
      timestamp: data.timestamp
    }
  };
}
